import { isFunction } from 'lodash-es'

const __SCRIPT_ACTION_FALLBACK = `
; if (!this.action) { try { this.action = action; } catch(e) {} }
`;

const __props = new WeakMap();
const {
  clear_angle,
  get_enemy_by_id,
  get_direction,
  get_shot_destination,
  angle_size,
  get_angle_control
} = require('./script_helpers')

export default class ScriptRunner {
  constructor(botId, context) {
    this.args = this.cache = {};

    __props.set(this, {
      botId: botId,
      registered: false,
      logGroup: `[ScriptRunner @${context.name}] Bot: <${botId}>: `
    });
  }

  get registered() {
    return __props.get(this).registered;
  }

  get logGroupName() {
    return __props.get(this).logGroup;
  }

  registerScript(_script_321) {
    if (this.registered) throw 'Script already registered';

    this.eval_context = {
      args: this.args,
      cache: this.cache,
      log: this.log.bind(this)
    };

    (function() {
      var __props = null;
      var args = this.args;
      var cache = this.cache;
      var log = this.log;

      try {
        eval(_script_321 + __SCRIPT_ACTION_FALLBACK);
      } catch (e) {
        console.error(e);
        throw new Error(e);
      }
    }).bind(this.eval_context)();

    this.action = this.eval_context.action;
    __props.get(this).registered = true;

    return true;
  }

  run() {
    if (!this.registered || !isFunction(this.action)) {
      throw 'Register script';
    }

    return this.action(...arguments[0]);
  }

  log() {
    if (console.log) console.log(this.logGroupName, ...arguments);
  }
}
