export function clear_angle(a) {
  return a > 0 ? a % 360 : a % 360 + 360;
}

export function get_enemy_by_id(id, enemies) {
  for (var i = 0; i < enemies.length; i++)
    if (enemies[i].id == id)
      return enemies[i];

  return false;
}

export function get_direction(fromx, fromy, tox, toy) {
  if (fromx - tox == 0)
    return fromy < toy ? 270 : 90;

  if (fromy - toy == 0)
    return fromx < tox ? 0 : 180;

  return clear_angle(-Math.atan2(toy - fromy, tox - fromx) * 180 / Math.PI);
}

export function get_shot_destination(shot) {
  return {
    x: shot.x + Math.cos(shot.angle / 180 * Math.PI) * shot.range,
    y: shot.y - Math.sin(shot.angle / 180 * Math.PI) * shot.range
  };
}

export function angle_size(a1, a2) {
  return Math.min(Math.abs(a1 - a2), Math.abs(Math.min(a1, a2) - Math.max(a1, a2) + 360));
}

export function get_angle_control(from, to) {
  var f = clear_angle(from);
  var t = clear_angle(to);
  var d = 1;

  if (angle_size(f + d, t) <= angle_size(f - d, t))
    return Math.min(angle_size(f, t), d);
  else
    return Math.max(-angle_size(f, t), -d);
}

