import ScriptRunner from './script_runner'
import { isString } from 'lodash-es'

export default class Service {
  constructor(context) {
    this.id = context.name || "undefined";
    this.context = context;
    this.runners = {};

    console.log(`[WorkerService #${this.id}] Registered`);
  }

  getHandler() {
    return this.handler.bind(this);
  }

  postMessage(id, payload, error) {
    return this.context.postMessage({
      id, payload, error
    });
  }

  handler(event) {
    const data = event.data;
    const { id: messageId, payload } = data;
    const [action, ...params] = payload;

    // console.log(`[WorkerService #${this.id}] Object received`, event.data);

    switch (action) {
      case 'register': {
        this.register(messageId, ...params);
        break;
      }

      case 'execute': {
        this.execute(messageId, ...params);
        break;
      }

      case 'ping': {
        this.postMessage(messageId, ['pong']);
        break;
      }

      default: {
        this.postMessage(messageId, [action, null], "Not supported worker action");
        throw `[WorkerService #${this.id}] ${action} is not supported worker action`
      }
    }
  }

  register(messageId, botId, script) {
    if (!isString(botId)) {
      this.postMessage(messageId, ['register', botId, { success: false }], "Invalid bot identifier");
      throw `[WorkerService #${this.id}] Bot "${botId}" is not valid identifier. Please use strings.`;
    }

    if (!this.runners[botId]) {
      const runner = new ScriptRunner(botId, this.context);

      try {
        runner.registerScript(script);
      } catch (e) {
        this.postMessage(messageId, ['register', botId, { success: false }], `Script evaluation error: ${e}`);
        throw new Error(`[WorkerService #${this.id}] Script evaluation error for "${botId}": ${e}\nStack: ${e.stack}`);
      }

      this.runners[botId] = runner;
      this.postMessage(messageId, ['register', botId, { success: true }]);

    } else {
      this.postMessage(messageId, ['register', botId, { success: false }], "Already registered");
      throw `[WorkerService #${this.id}] Bot "${botId}" already registered`;
    }
  }

  execute(messageId, botId, data) {
    const runner = this.runners[botId];
    let result = null;

    if (!runner) {
      this.postMessage(messageId, ['execute', botId, { success: false }], "Bot not found");
      throw `[WorkerService #${this.id}] Bot "${botId}" is not registered`;
    }

    try {
      result = runner.run(data);
    } catch (e) {
      this.postMessage(messageId, ['execute', botId, { success: false, stack: e.stack }], `Execution error: ${e}`);
      throw `[WorkerService #${this.id}] Execution error for "${botId}": ${e}\nStack: ${e.stack}`;
    }

    this.postMessage(messageId, ['execute', botId, { success: true, result: result }]);
  }
}
